noncompliant:
string userInput = GetUserInput();
string command = "ping";
string arguments = userInput; // Noncompliant: user input directly used as argument
Process.Start(command, arguments);

compliant:
string userInput = GetUserInput();
string command = "ping";
string safeArgument = Regex.Replace(userInput, @"[^\w\.-]", ""); // Compliant: sanitized input
Process.Start(command, safeArgument);
